+                .Add => " + ",
+                .Sub => " - ",
+                .Mult => " * ",
+                .Div => " / ",
+                .Mod => " % ",
+                .Pow => " ** ",
+                .BitAnd => " & ",
+                .BitOr => " | ",
+                .BitXor => " ^ ",
+                .LShift => " << ",
+                .RShift => " >> ",
+                .FloorDiv => " / ",
+                else => " ? ",
+            };
+            try self.emit(op_str);
+            try genExprWithSubs(self, b.right.*, subs);
+            try self.emit(")");
+        },
+        .constant => |c| {
+            switch (c.value) {
+                .int => |i| try self.output.writer(self.allocator).print("{d}", .{i}),
+                .float => |f| try self.output.writer(self.allocator).print("{d}", .{f}),
+                .string => |s| {
