+        .call => {
+            // Fallback to regular genExpr for complex expressions
+            const parent = @import("../expressions.zig");
+            try parent.genExpr(self, expr);
+        },
+        else => {
+            // For other expressions, fallback to regular genExpr
+            const parent = @import("../expressions.zig");
+            try parent.genExpr(self, expr);
+        },
+    }
